#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw*4;
    vec3 dx = ( 2*GetBlur1(vUv+vec2(1,0)*d)-2*GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( 2*GetBlur1(vUv+vec2(0,1)*d)-2*GetBlur1(vUv-vec2(0,1)*d) );
vec2 dz = vec2(dx.x,dy.x)*uTexSize.zw;

//ret = GetPixel(vUv);
ret = 0;
ret.x = tex2d(sampler_fw_main,vUv - dz).x - 0.0 - (GetBlur3(vUv).x-GetBlur1(vUv+dz).x) ;

dz = -vec2(dx.y,dy.y)*uTexSize.zw;
ret.y = tex2d(sampler_fw_main,vUv - dz).y - 0.06 - (GetBlur2(vUv).y-GetBlur1(vUv+dz).y)*1.3 ;

float zoom = 1.8-(audioLowSmooth-audioHighSmooth)*0.015;
vec2 cntr = vec2(0,0);
vec2 c = vec2(0.28,0.4);

 vec2 my_uv2 = (vUvOriginal-0.5-cntr)*zoom; // using vUvOriginal here - no contortion to the nice julia island
 my_uv2 = vec2(my_uv2.x*my_uv2.x - my_uv2.y*my_uv2.y, 2*my_uv2.x*my_uv2.y) + c; // u -> u^2 + c
vUv = my_uv2;
d = uTexSize.zw*4;
dx = ( 2*GetBlur1(vUv+vec2(1,0)*d)-2*GetBlur1(vUv-vec2(1,0)*d) );
dy = ( 2*GetBlur1(vUv+vec2(0,1)*d)-2*GetBlur1(vUv-vec2(0,1)*d) );
dz = vec2(dx.z,dy.z)*uTexSize.zw*1;

ret.z = GetPixel(clamp01(my_uv2+dz)).z - 0.014;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvo = vUv;

vec2 rotate_uv = 0.5-uv_rotate(0 + (vUv-0.5)*uAspect.xy, 0, q3, q4, 2);
vec2 bipolar_uv = uv_bipolar(rotate_uv,vec2(0,0.5),vec2(1,0.5), 2, 0.3, vec2(q11,q12));
vec2 mirror_uv = 0.5 + (0.5 - abs( fract( bipolar_uv * 0.5 ) * 2.0 - 1.0 ));

vec2 d = uTexSize.zw*3;
vec3 dx = ( 2*GetBlur1(mirror_uv+vec2(1,0)*d)-2*GetBlur1(mirror_uv-vec2(1,0)*d) );
vec3 dy = ( 2*GetBlur1(mirror_uv+vec2(0,1)*d)-2*GetBlur1(mirror_uv-vec2(0,1)*d) );

mirror_uv += vec2(dx.x,dy.x)*uTexSize.zw*4;

vec3 aura = pow(hue_shader,4)*1.4;
vec3 glow = 3;
vec3 blob = vec3(1,0.75,0)*0;

vec2 uv_red = mirror_uv;
ret = mix(ret,1,(GetBlur1(uv_red).x)*(1-GetBlur2(uv_red).x)*aura);
ret = mix(blob, ret, GetPixel(uv_red).x);
ret += (1-GetPixel(uv_red).x)*GetBlur1(uv_red).x*glow;

mirror_uv-= vec2(dx.x,dy.x)*uTexSize.zw*24;
dx = ( 2*GetBlur1(mirror_uv+vec2(1,0)*d)-2*GetBlur1(mirror_uv-vec2(1,0)*d) );
dy = ( 2*GetBlur1(mirror_uv+vec2(0,1)*d)-2*GetBlur1(mirror_uv-vec2(0,1)*d) );
vec2 dz = +vec2(-dx.y,dy.y)*0.25;
vec3 bg = mix(vec3(1,0.7,0.2),vec3(0.15,0,0.5),mirror_uv.x*0.8 - mirror_uv.y + 0.75+dz.x+dz.y-0.1)*(GetPixel(mirror_uv).y);
ret = mix(ret,1,bg);

mirror_uv = uv_rotate(0.5 + (uvo-0.5)*uAspect.wz, 0.5, q3, q4, 1).yx;

d = uTexSize.zw;
dx = ( 2*GetPixel(mirror_uv+vec2(1,0)*d)-2*GetPixel(mirror_uv-vec2(1,0)*d) );
dy = ( 2*GetPixel(mirror_uv+vec2(0,1)*d)-2*GetPixel(mirror_uv-vec2(0,1)*d) );
dz = -vec2(dx.z,dy.z);

ret = mix(ret,vec3(0.9,0.9,1),1-GetPixel(mirror_uv+dz).z) ;

  fragColor = ret;
}
